import{_ as n,o as t,c as a,ag as r}from"./chunks/framework.CvgP6Fyv.js";const b=JSON.parse('{"title":"Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"de/features/dashboard.md","filePath":"de/features/dashboard.md"}'),i={name:"de/features/dashboard.md"};function l(h,e,s,d,o,u){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h1><p>Das Dashboard ist Ihre Startseite in MyCompanyDesk. Es bietet Ihnen einen Überblick über Ihre Geschäftsfinanzen, Warnungen und Schnellaktionen auf einen Blick.</p><h2 id="dashboard-profile" tabindex="-1">Dashboard-Profile <a class="header-anchor" href="#dashboard-profile" aria-label="Permalink to &quot;Dashboard-Profile&quot;">​</a></h2><p>MyCompanyDesk bietet rollenbasierte Dashboard-Profile, die die angezeigten Kennzahlen und Karten an Ihre Bedürfnisse anpassen:</p><table tabindex="0"><thead><tr><th>Profil</th><th>Fokus</th></tr></thead><tbody><tr><td><strong>Inhaber / Geschäftsführer</strong></td><td>Cashflow, Rentabilität, Überblick auf hoher Ebene</td></tr><tr><td><strong>Buchhalter / Steuerberater</strong></td><td>USt., Compliance, Prüfpfade, Periodensperren</td></tr><tr><td><strong>Debitorenbuchhaltung (Rechnungsstellung)</strong></td><td>Rechnungskennzahlen, ausstehende Zahlungen</td></tr><tr><td><strong>Kreditorenbuchhaltung (Einkauf)</strong></td><td>Ausgabenverfolgung, Lieferantenverwaltung</td></tr><tr><td><strong>Freiberufler</strong></td><td>Vereinfachte Rechnungsstellung und Einnahmenverfolgung</td></tr><tr><td><strong>USt.-Compliance</strong></td><td>USt.-Berechnungen, Fristen, Meldungen</td></tr><tr><td><strong>Projektbasiert</strong></td><td>Projektrentabilität, Zeiterfassung</td></tr><tr><td><strong>Wachstum / Betrieb</strong></td><td>Umsatztrends, Kundenakquise</td></tr></tbody></table><h3 id="profil-wechseln" tabindex="-1">Profil wechseln <a class="header-anchor" href="#profil-wechseln" aria-label="Permalink to &quot;Profil wechseln&quot;">​</a></h3><ol><li>Öffnen Sie das Dashboard</li><li>Klicken Sie auf die Profilauswahl oben</li><li>Wählen Sie das Profil, das am besten zu Ihrer Rolle passt</li></ol><p>Jedes Profil zeigt unterschiedliche Kennzahlenkarten, Warnungen und Schnellaktionen, die für die jeweilige Rolle relevant sind.</p><h2 id="dashboard-bereiche" tabindex="-1">Dashboard-Bereiche <a class="header-anchor" href="#dashboard-bereiche" aria-label="Permalink to &quot;Dashboard-Bereiche&quot;">​</a></h2><h3 id="warnungen" tabindex="-1">Warnungen <a class="header-anchor" href="#warnungen" aria-label="Permalink to &quot;Warnungen&quot;">​</a></h3><p>Kritische Punkte, die Ihre Aufmerksamkeit erfordern:</p><ul><li>Überfällige Rechnungen</li><li>Bevorstehende USt.-Fristen</li><li>Auslaufende Verträge</li><li>Warnungen bei niedrigem Cashflow</li></ul><h3 id="wichtige-kennzahlen" tabindex="-1">Wichtige Kennzahlen <a class="header-anchor" href="#wichtige-kennzahlen" aria-label="Permalink to &quot;Wichtige Kennzahlen&quot;">​</a></h3><p>Übersichtskarten mit Ihren wichtigsten Zahlen:</p><ul><li>Gesamtumsatz (aktuelle Periode)</li><li>Ausstehende Rechnungen</li><li>Gesamtausgaben</li><li>Nettogewinn/-verlust</li><li>Offene Angebote</li></ul><h3 id="periodenauswahl" tabindex="-1">Periodenauswahl <a class="header-anchor" href="#periodenauswahl" aria-label="Permalink to &quot;Periodenauswahl&quot;">​</a></h3><p>Wechseln Sie zwischen verschiedenen Zeiträumen, um Ihre Kennzahlen anzuzeigen:</p><ul><li>Diese Woche / Monat / Quartal / Jahr</li><li>Benutzerdefinierter Datumsbereich</li><li>Vergleich mit vorherigen Perioden</li></ul><h3 id="schnellaktionen" tabindex="-1">Schnellaktionen <a class="header-anchor" href="#schnellaktionen" aria-label="Permalink to &quot;Schnellaktionen&quot;">​</a></h3><p>Verknüpfungen zu Ihren häufigsten Aufgaben:</p><ul><li>Neue Rechnung erstellen</li><li>Ausgabe hinzufügen</li><li>Zeiteintrag erfassen</li><li>Berichte anzeigen</li></ul><h3 id="letzte-aktivitaten" tabindex="-1">Letzte Aktivitäten <a class="header-anchor" href="#letzte-aktivitaten" aria-label="Permalink to &quot;Letzte Aktivitäten&quot;">​</a></h3><p>Ein Feed der neuesten Ereignisse in Ihrem Arbeitsbereich:</p><ul><li>Rechnungen gesendet und bezahlt</li><li>Ausgaben hinzugefügt</li><li>Kunden erstellt</li><li>Aktionen von Teammitgliedern</li></ul><h2 id="onboarding-karte" tabindex="-1">Onboarding-Karte <a class="header-anchor" href="#onboarding-karte" aria-label="Permalink to &quot;Onboarding-Karte&quot;">​</a></h2><p>Neue Benutzer sehen eine Onboarding-Karte, die sie durch die Ersteinrichtung führt:</p><ol><li>Unternehmensinformationen einrichten</li><li>Ersten Kunden hinzufügen</li><li>Erste Rechnung erstellen</li></ol><p>Die Karte verfolgt Ihren Fortschritt und verschwindet nach Abschluss (oder bei manueller Ausblendung).</p>',28)])])}const g=n(i,[["render",l]]);export{b as __pageData,g as default};
